import{_ as e,o as t,c as o,a0 as r}from"./chunks/framework.jwovEGr5.js";const c=JSON.parse('{"title":"비스타즈","description":"","frontmatter":{},"headers":[],"relativePath":"outta-space/knowledge/animations/비스타즈.md","filePath":"outta-space/knowledge/animations/비스타즈.md"}'),n={name:"outta-space/knowledge/animations/비스타즈.md"};function i(l,a,s,_,d,h){return t(),o("div",null,[...a[0]||(a[0]=[r('<h1 id="비스타즈" tabindex="-1">비스타즈 <a class="header-anchor" href="#비스타즈" aria-label="Permalink to &quot;비스타즈&quot;">​</a></h1><h2 id="_1-이야기와-전개" tabindex="-1">1. 이야기와 전개 <a class="header-anchor" href="#_1-이야기와-전개" aria-label="Permalink to &quot;1. 이야기와 전개&quot;">​</a></h2><p>초식 동물과 육식 동물이 함께 살아가는 사회를 배경으로, 본능과 사회성의 충돌을 다루는 애니메이션이다.</p><p>초반 진입장벽은 꽤 높다. 사슴과 토끼가 야스하는 장면을 봐야 한다는 점에서 시작부터 강한 취향 장벽이 있다.</p><h2 id="_2-캐릭터와-감정선" tabindex="-1">2. 캐릭터와 감정선 <a class="header-anchor" href="#_2-캐릭터와-감정선" aria-label="Permalink to &quot;2. 캐릭터와 감정선&quot;">​</a></h2><p>캐릭터의 감정선은 쉽게 받아들이기 어렵지만, 그 불편함이 작품의 핵심이기도 하다.</p><p>레고시는 너무 특이한 케이스라 공감이 잘 되지 않았고, 암거래 시장 같은 설정은 현실의 일상적 질서와 비교했을 때 지나치게 큰 문제처럼 느껴졌다. 이 새끼들이 사회에서 잘 지낼 생각이 있는 건지 의문이 들 정도로 본능과 충돌이 크게 그려진다.</p><h2 id="_3-작화와-영상미" tabindex="-1">3. 작화와 영상미 <a class="header-anchor" href="#_3-작화와-영상미" aria-label="Permalink to &quot;3. 작화와 영상미&quot;">​</a></h2><p>동물 의인화와 3D 애니메이션 특유의 질감이 강하다. 취향을 많이 타지만, 작품의 기괴하고 불편한 분위기와는 잘 맞는다.</p><h2 id="_4-음악과-성우-연기" tabindex="-1">4. 음악과 성우 연기 <a class="header-anchor" href="#_4-음악과-성우-연기" aria-label="Permalink to &quot;4. 음악과 성우 연기&quot;">​</a></h2><p>음악과 성우 연기는 작품의 긴장감과 이질감을 잘 살린다. 특히 레고시의 내면 갈등은 연기를 통해 어느 정도 설득력을 얻는다.</p><h2 id="_5-주제와-여운" tabindex="-1">5. 주제와 여운 <a class="header-anchor" href="#_5-주제와-여운" aria-label="Permalink to &quot;5. 주제와 여운&quot;">​</a></h2><p>본능, 사회성, 성욕, 식욕, 폭력성 같은 주제를 정면으로 다룬다. 이 작품은 퍼리에 대한 본능을 일깨우는 작품처럼 느껴질 정도로, 동물성과 인간성을 노골적으로 겹쳐 보여준다.</p><p>다만 이야기의 큰 흐름은 생각보다 와닿지 않았고, 마지막 시즌이 나온다고 해도 메론이라는 인물이 잘 잡히지 않아 기대가 크지는 않다.</p><p>한 줄 평: 본능과 사회성을 불편하게 겹쳐 보여주는 독특한 작품이지만, 진입장벽과 캐릭터 공감 장벽이 높다.</p>',15)])])}const u=e(n,[["render",i]]);export{c as __pageData,u as default};
